-- set incroci
UPDATE collegamentotratte CT INNER JOIN collegamentotratte CT2 ON ( CT.Latitudine = CT2.Latitudine AND CT.Longitudine = CT2.Longitudine AND CT.Altitudine = CT2.Altitudine)
SET CT.Incrocio = 1
WHERE CT.CodTratta <> CT2.CodTratta;

